parameters.jsCode:
const proposal = $input.item.json[0];
if (!proposal) throw new Error('Proposal not found');

const client = proposal.clients || {};
const briefing = proposal.briefings || {};
const raw = briefing.raw_data || {};

const approvalUrl = `${$env.N8N_WEBHOOK_BASE_URL}/webhook/proposal-response?proposal_id=${proposal.id}&decision=approved`;
const rejectionUrl = `${$env.N8N_WEBHOOK_BASE_URL}/webhook/proposal-response?proposal_id=${proposal.id}&decision=rejected`;

const packageLabels = {
  ia: 'IA — Geração de Conteúdo',
  art: 'A-R-T — FunWheel Completo',
  e: 'E — Página de Vendas',
  combo_leads: 'Combo Leads — IA + A-R-T',
  combo_cash: 'Combo Cash — Funil Completo'
};

return [{
  json: {
    proposal_id: proposal.id,
    briefing_id: proposal.briefing_id,
    client_name: client.name || raw.nome_negocio || 'Cliente',
    client_email: client.email || raw.email,
    client_phone: raw.canal_comunicacao === 'WhatsApp' ? raw.phone : null,
    package_label: packageLabels[proposal.package] || proposal.package,
    reasoning: proposal.reasoning,
    timeline: proposal.timeline,
    cost_range: proposal.cost_range,
    approval_url: approvalUrl,
    rejection_url: rejectionUrl
  }
}];

